{"type":"assistant","message":{"content":[{"id":"tooluse_VMg3oYdawvCOAfVFTXw2LP","input":{"file_path":"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_35_low_drawdown_growth/revised/claudecode/analyze_stocks.py","content":"#!/usr/bin/env python3\n\"\"\"\n低回撤稳健成长股筛选\n筛选条件：\n1. 60日收益率 > 20%\n2. 最大回撤 < 12%\n3. Calmar比率 > 2\n4. 连续下跌天数不超过5天\n5. 单日最大跌幅 < 6%\n6. 近20日上涨天数占比 > 55%\n\"\"\"\n\nimport akshare as ak\nimport pandas as pd\nimport numpy as np\nfrom datetime import datetime, timedelta\nimport warnings\nwarnings.filterwarnings('ignore')\n\ndef calculate_max_drawdown(prices):\n    \"\"\"计算最大回撤\"\"\"\n    cummax = prices.cummax()\n    drawdown = (cummax - prices) / cummax * 100\n    return drawdown.max()\n\ndef calculate_consecutive_down_days(returns):\n    \"\"\"计算最长连续下跌天数\"\"\"\n    max_consecutive = 0\n    current_consecutive = 0\n\n    for ret in returns:\n        if ret < 0:\n            current_consecutive += 1\n            max_consecutive = max(max_consecutive, current_consecutive)\n        else:\n            current_consecutive = 0\n\n    return max_consecutive\n\ndef calculate_win_rate_20d(returns):\n    \"\"\"计算近20日上涨天数占比\"\"\"\n    if len(returns) < 20:\n        return 0\n    last_20 = returns[-20:]\n    up_days = (last_20 > 0).sum()\n    return (up_days / 20) * 100\n\ndef analyze_stock(stock_code, start_date, end_date):\n    \"\"\"分析单只股票\"\"\"\n    try:\n        # 获取股票历史数据（前复权）\n        df = ak.stock_zh_a_hist(\n            symbol=stock_code,\n            period=\"daily\",\n            start_date=start_date,\n            end_date=end_date,\n            adjust=\"qfq\"\n        )\n\n        if df is None or len(df) < 60:\n            return None\n\n        # 取最近60个交易日\n        df = df.tail(60).copy()\n\n        if len(df) < 60:\n            return None\n\n        # 计算收益率\n        close_prices = df['收盘'].values\n        returns = np.diff(close_prices) / close_prices[:-1] * 100\n\n        # 1. 60日总收益率\n        return_60d = (close_prices[-1] - close_prices[0]) / close_prices[0] * 100\n\n        if return_60d <= 20:\n            return None\n\n        # 2. 最大回撤\n        max_dd = calculate_max_drawdown(pd.Series(close_prices))\n\n        if max_dd >= 12:\n            return None\n\n        # 3. 年化收益率和Calmar比率\n        annual_return = return_60d * (252 / 60)\n        calmar_ratio = annual_return / max_dd if max_dd > 0 else 0\n\n        if calmar_ratio <= 2:\n            return None\n\n        # 4. 连续下跌天数\n        max_consecutive_down = calculate_consecutive_down_days(returns)\n\n        if max_consecutive_down > 5:\n            return None\n\n        # 5. 单日最大跌幅\n        max_single_drop = abs(returns.min())\n\n        if max_single_drop >= 6:\n            return None\n\n        # 6. 近20日胜率\n        win_rate_20d = calculate_win_rate_20d(returns)\n\n        if win_rate_20d <= 55:\n            return None\n\n        return {\n            'code': stock_code,\n            'return_60d': return_60d,\n            'max_drawdown': max_dd,\n            'annual_return': annual_return,\n            'calmar_ratio': calmar_ratio,\n            'win_rate_20d': win_rate_20d\n        }\n\n    except Exception as e:\n        return None\n\ndef main():\n    \"\"\"主函数\"\"\"\n    # 设置日期范围\n    end_date = '20240722'\n    # 获取更多天数以确保有足够的交易日\n    start_date = '20240401'\n\n    print(\"正在获取创业板股票列表...\")\n\n    # 获取所有A股列表\n    stock_list = ak.stock_zh_a_spot_em()\n\n    # 筛选创业板股票（300开头）\n    chinext_stocks = stock_list[stock_list['代码'].str.startswith('300')]['代码'].tolist()\n\n    print(f\"找到 {len(chinext_stocks)} 只创业板股票\")\n    print(\"开始分析...\")\n\n    results = []\n\n    for i, stock_code in enumerate(chinext_stocks):\n        if (i + 1) % 50 == 0:\n            print(f\"已处理 {i + 1}/{len(chinext_stocks)} 只股票...\")\n\n        result = analyze_stock(stock_code, start_date, end_date)\n\n        if result:\n            results.append(result)\n\n    print(f\"\\n符合条件的股票数量: {len(results)}\")\n\n    if len(results) == 0:\n        # 如果没有符合条件的股票\n        with open('calmar_top10.txt', 'w', encoding='utf-8') as f:\n            f.write(\"无符合条件的股票\\n\")\n        print(\"未找到符合所有条件的股票\")\n        return\n\n    # 按Calmar比率排序\n    results_df = pd.DataFrame(results)\n    results_df = results_df.sort_values('calmar_ratio', ascending=False)\n\n    # 取前10只\n    top10 = results_df.head(10)\n\n    # 写入文件\n    with open('calmar_top10.txt', 'w', encoding='utf-8') as f:\n        f.write(\"股票代码,60日收益率(%),最大回撤(%),年化收益率(%),Calmar比率,近20日胜率(%)\\n\")\n\n        for _, row in top10.iterrows():\n            f.write(f\"{row['code']},{row['return_60d']:.1f},{row['max_drawdown']:.1f},\"\n                   f\"{row['annual_return']:.1f},{row['calmar_ratio']:.1f},{row['win_rate_20d']:.1f}\\n\")\n\n    print(\"\\n结果已写入 calmar_top10.txt\")\n    print(\"\\n前10只股票:\")\n    print(top10.to_string(index=False))\n\nif __name__ == \"__main__\":\n    main()\n"},"name":"Write","type":"tool_use"}],"id":"ff19887b-bbe8-4a4a-9ad3-487ddd59d86c","model":"claude-sonnet-4-6","role":"assistant","stop_reason":null,"stop_sequence":null,"type":"message","usage":{"cache_creation_input_tokens":1361,"cache_read_input_tokens":0,"input_tokens":9412,"output_tokens":0},"context_management":null},"parent_tool_use_id":null,"session_id":"838c5253-875d-42a8-afce-38ce0ffd9854","uuid":"8c083d2e-8703-4860-bde3-8f33f3bdee21"}
